import React from "react";
import styles from "./summary-info.module.css";

interface InfoProps {

  showContact: boolean;
  showAddress: boolean;
  showShippingMethod: boolean;
}

const SummaryInfo: React.FC<InfoProps> = ({
  address,
  shippingMethod,
  showContact,
  showAddress,
  showShippingMethod,
}) => {
  return (
    <div className={styles.summary_info}>
      {showContact && (
        <>
          <span className={styles.info}>
            <div className={styles.info_left}>
              <h6 className={styles.info_title}>Contact:</h6>
            </div>
            <button type="button" className={styles.btn_edit}>
              Edit
            </button>
          </span>
          <div className={styles.divider} />
        </>
      )}
      {(showAddress || showShippingMethod) && (
        <>
          <span className={styles.info}>
            <div className={styles.info_left}>
              <h6 className={styles.info_title}>Ship to:</h6>
              <p className={styles.info_text}>
                {address}
                {showShippingMethod && <br />}
                {showShippingMethod && (
                  <>
                    <strong>Shipping Method:</strong> {shippingMethod}
                  </>
                )}
              </p>
            </div>
            <button type="button" className={styles.btn_edit}>
              Edit
            </button>
          </span>
          <div className={styles.divider} />
        </>
      )}
    </div>
  );
};

export default SummaryInfo;




